ng": false, "muting": false}, "rest_id": "2061493691630387201", "super_follow_eligible": false, "super_followed_by": false, "super_following": false, "verification": {"verified": false}}}}, "edit_control": {"edit_tweet_ids": ["2072769435668979837"], "editable_until_msecs": "1783025318000", "edits_remaining": "5", "is_edit_eligible": false}, "grok_analysis_button": true, "is_translatable": false, "legacy": {"bookmark_count": 0, "bookmarked": false, "conversation_id_str": "2072760446617280650", "created_at": "Thu Jul 02 19:48:38 +0000 2026", "display_text_range": [16, 292], "entities": {"user_mentions": [{"id_str": "1940360837547565056", "indices": [0, 15], "name": "Serenity", "screen_name": "aleabitoreddit"}]}, "favorite_count": 4, "favorited": false, "full_text": "@aleabitoreddit Man, seeing semis get hammered again on what’s basically old Meta news is wild. I think Bloomberg just loves stirring the pot, UBS called it right, Zuckerberg talked about selling capacity ages ago. Those $48B neocloud deals don’t scream overbuild to me. I believe the real AI", "id_str": "2072769435668979837", "in_reply_to_screen_name": "aleabitoreddit", "in_reply_to_status_id_str": "2072760446617280650", "in_reply_to_user_id_str": "1940360837547565056", "is_quote_status": false, "lang": "en", "quote_count": 0, "reply_count": 2, "retweet_count": 0, "retweeted": false, "user_id_str": "2061493691630387201"}, "note_tweet": {"is_expandable": true, "note_tweet_results": {"result": {"entity_set": {"hashtags": [], "symbols": [{"indices": [322, 327], "text": "AAOI"}, {"indices": [332, 337], "text": "MRVL"}, {"indices": [620, 625], "text": "AEHR"}, {"indices": [792, 797], "text": "META"}, {"indices": [887, 892], "text": "AAOI"}, {"indices": [893, 899], "text": "SIVEF"}, {"indices": [900, 905], "text": "LITE"}, {"indices": [907, 911], "text": "TER"}], "urls": [], "user_mentions": []}, "id": "Tm90ZVR3ZWV0OjIwNzI3Njk0MzU1NTk5ODEwNTY=", "text": "Man, seeing semis get hammered again on what’s basically old Meta news is wild. I think Bloomberg just loves stirring the pot, UBS called it right, Zuckerberg talked about selling capacity ages ago. Those $48B neocloud deals don’t scream overbuild to me. I believe the real AI demand is still there, so I’m eyeing dips in $AAOI and $MRVL.

I’ve seen this movie before with the AMD/Nvidia export scare earlier this year. Markets overreact every time. I think this is weak hands folding while the big picture (power shortages, compute needs) hasn’t changed. Personally believe loading up on the AI supply chain names like $AEHR and photonics plays here could pay off big once the noise dies.

Honestly, semis trade on headlines more than reality short term. I believe this selloff is overdone, $META optimizing capacity isn’t the same as slashing AI spend. I think we’re getting a gift on $AAOI $SIVEF $LITE, $TER, etc. Staying long the thesis, volatility like this separates the believers from the rest."}}}, "rest_id": "2072769435668979837", "source": "<a href="http://twitter.com/download/android" rel="nofollow">Twitter for Android</a>", "unmention_data": {}, "views": {"count": "1132", "state": "EnabledWithCount"}}

